// BIND named configuration for ns1.internal.corp
// Generated by dnsadmin on 2026-01-15

acl "trusted" {
    10.0.6.0/24;
    10.0.7.0/24;
    10.0.8.0/24;
    127.0.0.1;
};

options {
    listen-on port 53 { 127.0.0.1; 10.0.6.2; };
    listen-on-v6 port 53 { ::1; };
    directory       "/var/named";
    dump-file       "/var/named/data/cache_dump.db";
    statistics-file "/var/named/data/named_stats.txt";
    memstatistics-file "/var/named/data/named_mem_stats.txt";
    secroots-file   "/var/named/data/named.secroots";
    recursing-file  "/var/named/data/named.recursing";
    allow-query     { trusted; };
    allow-transfer  { 10.0.6.3; key transfer-key; };
    allow-update    { key update-key; };
    recursion yes;
    dnssec-validation yes;
    managed-keys-directory "/var/named/dynamic";
    pid-file "/run/named/named.pid";
    session-keyfile "/run/named/session.key";
};

logging {
    channel default_log {
        file "/var/log/named/named.log" versions 5 size 50m;
        severity info;
        print-time yes;
        print-category yes;
        print-severity yes;
    };
    channel query_log {
        file "/var/log/named/queries.log" versions 10 size 100m;
        severity dynamic;
        print-time yes;
    };
    category default { default_log; };
    category queries { query_log; };
};

include "/etc/named/keys/tsig-key.conf";
include "/etc/named/keys/rndc.key";

controls {
    inet 127.0.0.1 port 953 allow { 127.0.0.1; } keys { "rndc-key"; };
};

zone "." IN {
    type hint;
    file "named.ca";
};

zone "internal.corp" IN {
    type master;
    file "/etc/named/zones/internal.corp.zone";
    allow-update { key update-key; };
    allow-transfer { 10.0.6.3; key transfer-key; };
    also-notify { 10.0.6.3; };
};

zone "6.0.10.in-addr.arpa" IN {
    type master;
    file "/etc/named/zones/6.0.10.in-addr.arpa.zone";
    allow-update { key update-key; };
    allow-transfer { 10.0.6.3; key transfer-key; };
};
